import { useMemo, useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";

const FAQS = [
  { q: "What is scientific notation?", a: "Scientific notation writes a number as a coefficient between 1 and 10 multiplied by a power of 10, such as 3.2 x 10^5." },
  { q: "How do you convert a number to scientific notation?", a: "Move the decimal point until one nonzero digit remains to its left. The number of places moved becomes the exponent of 10." },
  { q: "How do you multiply numbers in scientific notation?", a: "Multiply the coefficients and add the exponents. Then normalize the result so the coefficient is between 1 and 10." },
  { q: "When is scientific notation used?", a: "Scientific notation is used for very large or very small values in science, engineering, astronomy, chemistry, and math." },
  { q: "What is the difference between scientific notation and standard form?", a: "Scientific notation uses a coefficient and power of 10. Standard form is the ordinary decimal number." },
];

type Mode = "convert" | "math";
type Operation = "add" | "subtract" | "multiply" | "divide";
const fmt = (n: number) => Number.isFinite(n) ? n.toPrecision(12).replace(/\.?0+($|e)/, "$1") : "Invalid";
const toSci = (n: number) => {
  if (!Number.isFinite(n)) return { coeff: NaN, exp: 0, text: "Invalid" };
  if (n === 0) return { coeff: 0, exp: 0, text: "0 x 10^0" };
  const exp = Math.floor(Math.log10(Math.abs(n)));
  const coeff = n / 10 ** exp;
  return { coeff, exp, text: `${fmt(coeff)} x 10^${exp}` };
};
const fromSci = (coeff: number, exp: number) => coeff * 10 ** exp;

export default function ScientificNotationCalculator() {
  const [mode, setMode] = useState<Mode>("convert");
  const [number, setNumber] = useState(1230000);
  const [coeffA, setCoeffA] = useState(3.2);
  const [expA, setExpA] = useState(5);
  const [coeffB, setCoeffB] = useState(4);
  const [expB, setExpB] = useState(3);
  const [operation, setOperation] = useState<Operation>("multiply");
  const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";

  const result = useMemo(() => {
    if (mode === "convert") {
      const sci = toSci(number);
      return { label: "Scientific Notation", value: sci.text, standard: fmt(number), step: `Move the decimal in ${number} to make ${fmt(sci.coeff)}. It moved ${sci.exp} places, so the result is ${sci.text}.` };
    }
    const a = fromSci(coeffA, expA);
    const b = fromSci(coeffB, expB);
    const value = operation === "add" ? a + b : operation === "subtract" ? a - b : operation === "multiply" ? a * b : a / b;
    const sci = toSci(value);
    const symbol = operation === "add" ? "+" : operation === "subtract" ? "-" : operation === "multiply" ? "x" : "/";
    return { label: "Result", value: sci.text, standard: fmt(value), step: `(${coeffA} x 10^${expA}) ${symbol} (${coeffB} x 10^${expB}) = ${fmt(value)} = ${sci.text}.` };
  }, [mode, number, coeffA, expA, coeffB, expB, operation]);

  return (
    <>
      <SEOHead title="Free Scientific Notation Calculator Online - Convert and Calculate Scientific Notation Instantly | CalcHive" description="Free online scientific notation calculator. Convert numbers to and from scientific notation and perform math operations on them instantly. 100% free for students, no signup required." canonical="/scientific-notation-calculator" keywords="free scientific notation calculator, scientific notation converter free online, convert to scientific notation free, scientific notation math calculator free, standard form calculator free" category="Math Calculators" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-amber-600 dark:text-amber-400 bg-amber-50 dark:bg-amber-950/50 px-3 py-1 rounded-full mb-4 inline-block">Math</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Scientific Notation Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Use this free scientific notation calculator to convert to scientific notation free and perform scientific notation math.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8">
            <div><label htmlFor="mode" className="text-sm font-semibold text-foreground block mb-2">Mode</label><select id="mode" value={mode} onChange={(e) => setMode(e.target.value as Mode)} className={inputClass}><option value="convert">Convert number</option><option value="math">Scientific notation math</option></select></div>
            {mode === "convert" ? <div><label htmlFor="number" className="text-sm font-semibold text-foreground block mb-2">Number</label><input id="number" type="number" value={number} onChange={(e) => setNumber(Number(e.target.value))} className={inputClass} /></div> : <div><label htmlFor="operation" className="text-sm font-semibold text-foreground block mb-2">Operation</label><select id="operation" value={operation} onChange={(e) => setOperation(e.target.value as Operation)} className={inputClass}><option value="add">Add</option><option value="subtract">Subtract</option><option value="multiply">Multiply</option><option value="divide">Divide</option></select></div>}
          </div>
          {mode === "math" && <div className="grid grid-cols-2 sm:grid-cols-4 gap-4 mb-8">
            <div><label className="text-sm font-semibold text-foreground block mb-2">Coeff A</label><input type="number" value={coeffA} onChange={(e) => setCoeffA(Number(e.target.value))} className={inputClass} /></div>
            <div><label className="text-sm font-semibold text-foreground block mb-2">Exp A</label><input type="number" value={expA} onChange={(e) => setExpA(Number(e.target.value))} className={inputClass} /></div>
            <div><label className="text-sm font-semibold text-foreground block mb-2">Coeff B</label><input type="number" value={coeffB} onChange={(e) => setCoeffB(Number(e.target.value))} className={inputClass} /></div>
            <div><label className="text-sm font-semibold text-foreground block mb-2">Exp B</label><input type="number" value={expB} onChange={(e) => setExpB(Number(e.target.value))} className={inputClass} /></div>
          </div>}
          <motion.div key={`${mode}-${result.value}-${result.standard}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="bg-gradient-to-br from-amber-500 to-amber-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">{result.label}</p><p className="text-4xl font-black text-white tracking-tight break-words" data-testid="result-scientific-notation">{result.value}</p><p className="text-white/70 text-sm mt-1">Standard form: {result.standard}</p></div>
            <div className="mt-4 bg-accent/60 border border-border rounded-xl p-4"><p className="text-xs font-bold uppercase tracking-wide text-muted-foreground mb-2">Step by step</p><p className="text-sm text-foreground" data-testid="result-steps">{result.step}</p></div>
          </motion.div>
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6"><h2 className="text-2xl font-bold text-foreground">How to Convert Numbers to Scientific Notation for Free</h2><p className="text-muted-foreground leading-relaxed">Enter any number and this scientific notation converter free online tool rewrites it as a coefficient times a power of 10.</p><h2 className="text-2xl font-bold text-foreground">How to Add Subtract Multiply and Divide in Scientific Notation</h2><p className="text-muted-foreground leading-relaxed">The calculator converts each scientific notation value to standard form, performs the operation, then normalizes the answer.</p><h2 className="text-2xl font-bold text-foreground">Free Scientific Notation Tool for Students</h2><p className="text-muted-foreground leading-relaxed">Use this standard form calculator free for chemistry, physics, astronomy, and math homework.</p></section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/scientific-notation-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


